module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

    reg [7:0] sum_tmp1, sum_tmp2;
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            sum_tmp1 <= 8'd0;
            sum_tmp2 <= 8'd0;
        end
        else begin
            sum_tmp1 <= ((mul_b[0] ? mul_a : 4'd0) + (mul_b[1] ? mul_a << 1 : 4'd0));
            sum_tmp2 <= ((mul_b[2] ? mul_a << 2 : 4'd0) + (mul_b[3] ? mul_a << 3 : 4'd0));
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            mul_out <= 8'd0;
        end
        else begin
            mul_out <= sum_tmp1 + sum_tmp2;
        end
    end
endmodule
